function simulateStack(arr, element) {
  // 1. Push 'element' to 'arr'
  // 2. Pop from 'arr'
  // 3. Push 'element' again
  // 4. Return arr
}

solution:
function simulateStack(arr, element) {
  arr.push(element);
  arr.pop();
  arr.push(element);
  return arr;
}

