function rotateArray(arr, k) {
  if (arr.length === 0) return arr;
  // 1. k = k % arr.length
  // 2. splice the last k elements
  // 3. unshift them back
  // 4. return arr
}

solution:
function rotateArray(arr, k) {
  if (arr.length === 0) return arr;
  const steps = k % arr.length;
  const rightPart = arr.splice(-steps);
  arr.unshift(...rightPart);
  return arr;
}

