  // 3. Sort descending
  // 4. Return index 1
}

solution:
function findSecondLargest(arr) {
  const unique = Array.from(new Set(arr));
  if (unique.length < 2) return null;
  unique.sort((a, b) => b - a);
  return unique[1];
}

